/**
 * POST/GET /api/cron/auto-article
 *
 * Cron endpoint: produce ONE auto-generated article draft per chosen
 * TargetKeyword by RESEARCHING THE LIVE WEB with Perplexity (sonar-pro).
 * Protected by `Authorization: Bearer ${CRON_SECRET}`.
 *
 * Provider: Perplexity ONLY (no DeepSeek/Claude here — per editor request
 * 2026-06-04). Perplexity is web-grounded, so each draft is a fresh,
 * source-cited article about the keyword rather than a reword of an existing
 * Kartawarta article. The web sources Perplexity used are stored as the
 * article's Sources for attribution.
 *
 * Flow:
 *   1. Check `SystemSetting.auto_article_enabled === "true"` — else skip
 *   2. Pick random active keyword (priority desc, random from top 10)
 *   3. generateArticleViaPerplexity(keyword) → title/body/excerpt/tags/seo + sources
 *   4. Create Article status=DRAFT, isAutoGenerated=true, UNVERIFIED, with the
 *      cited web sources + a Perplexity web image as featured image when present
 *   5. Update keyword.lastGeneratedAt + audit log
 *
 * If Perplexity is not configured (no `perplexity_api_key`) the run skips that
 * keyword with a clear reason — it never falls back to another provider.
 *
 * All errors are trapped: endpoint always returns HTTP 200 with
 * `{success:false, error}` on failure so cron doesn't retry-spam.
 *
 * Recommend invocation: every 1 hour.
 */

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { slugify } from "@/lib/utils";
import { sanitizeHtml } from "@/lib/sanitize";
import { verifyCronSecret, errorResponse, logAudit } from "@/lib/api-utils";
import { trackCron } from "@/lib/cron-tracker";
import { tryAdvisoryLock, releaseAdvisoryLock } from "@/lib/cron-lock";
import { extractFirstImageUrl } from "@/lib/image-extract";
import { generateArticleViaPerplexity } from "@/lib/perplexity-article";
import * as Sentry from "@sentry/nextjs";

/** Escape a string for use in an HTML attribute value (double-quoted). */
function escapeHtmlAttr(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/"/g, "&quot;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

export const dynamic = "force-dynamic";
export const maxDuration = 300;

/** Hostname (sans www) for use as a Source.name. */
function hostnameOf(url: string): string {
  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return "sumber";
  }
}

/** Dedupe cited sources by URL, preserving order. */
function dedupeSources(
  sources: { url: string; title: string | null }[],
): { url: string; title: string | null }[] {
  const seen = new Set<string>();
  const out: { url: string; title: string | null }[] = [];
  for (const s of sources) {
    if (!s.url || seen.has(s.url)) continue;
    seen.add(s.url);
    out.push(s);
  }
  return out;
}

async function uniqueSlug(base: string): Promise<string> {
  const root = slugify(base).slice(0, 90) || "artikel";
  const existing = await prisma.article.findUnique({
    where: { slug: root },
    select: { id: true },
  });
  if (!existing) return root;
  const suffix = Math.random().toString(36).slice(2, 8);
  return `${root}-${suffix}`;
}

// Read SystemSetting with default fallback. Empty string and missing rows
// both fall back to the default.
async function readSetting(key: string, fallback: string): Promise<string> {
  try {
    const row = await prisma.systemSetting.findUnique({ where: { key } });
    if (!row || !row.value) return fallback;
    return row.value;
  } catch {
    return fallback;
  }
}

async function writeSetting(key: string, value: string): Promise<void> {
  try {
    await prisma.systemSetting.upsert({
      where: { key },
      update: { value },
      create: { key, value },
    });
  } catch {
    /* swallow */
  }
}

// Generate ONE auto-article. Returns null on skip (with reason logged in
// the result); caller (the batch loop) treats null as "this slot didn't
// produce, try next". Errors that should abort the whole batch throw.
type GenerateResult =
  | { ok: true; articleId: string; slug: string; title: string; keyword: string; provider: string; tokens: number }
  | { ok: false; reason: string; keyword?: string };

async function generateOne(): Promise<GenerateResult> {
  // Pick keyword (random from top-10 active by priority).
  const keywords = await prisma.targetKeyword.findMany({
    where: { isActive: true },
    orderBy: { priority: "desc" },
    take: 10,
  });
  if (keywords.length === 0) {
    return { ok: false, reason: "no-active-keywords" };
  }
  const kw = keywords[Math.floor(Math.random() * keywords.length)];

  // Generate a FRESH, web-grounded article via Perplexity ONLY.
  let gen;
  try {
    gen = await generateArticleViaPerplexity(kw.keyword);
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return {
      ok: false,
      reason:
        msg === "PERPLEXITY_NOT_CONFIGURED"
          ? "perplexity-not-configured (set perplexity_api_key di Pengaturan → AI)"
          : `perplexity-failed: ${msg}`,
      keyword: kw.keyword,
    };
  }

  // Validate output — need a title and a body of reasonable length.
  const plainLen = gen.content.replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim().length;
  if (!gen.title.trim() || plainLen < 200) {
    return {
      ok: false,
      reason: `perplexity-output-too-short (title=${gen.title.trim() ? "y" : "n"}, len=${plainLen})`,
      keyword: kw.keyword,
    };
  }

  // Resolve author: SystemSetting override → first SUPER_ADMIN → skip.
  let authorId: string | null = null;
  const authorIdSetting = await readSetting("auto_article_author_id", "");
  if (authorIdSetting) {
    const exists = await prisma.user.findUnique({
      where: { id: authorIdSetting },
      select: { id: true },
    });
    if (exists) authorId = exists.id;
  }
  if (!authorId) {
    const admin = await prisma.user.findFirst({
      where: { role: "SUPER_ADMIN" },
      orderBy: { createdAt: "asc" },
      select: { id: true },
    });
    authorId = admin?.id ?? null;
  }
  if (!authorId) {
    return { ok: false, reason: "no-author-resolved", keyword: kw.keyword };
  }

  // Category: keyword override → first category as fallback (Article.categoryId
  // is required, and a web-generated article has no source category to inherit).
  let categoryId = kw.categoryId;
  if (!categoryId) {
    const firstCat = await prisma.category.findFirst({
      orderBy: { order: "asc" },
      select: { id: true },
    });
    if (!firstCat) {
      return { ok: false, reason: "no-category-available", keyword: kw.keyword };
    }
    categoryId = firstCat.id;
  }

  // Featured image: prefer a Perplexity web image (http(s) only), else extract
  // the first inline image from the generated body.
  const pplxImage = gen.images.find((im) => /^https?:\/\//i.test(im.imageUrl))?.imageUrl ?? null;
  const featuredImage = pplxImage || extractFirstImageUrl(gen.content) || null;

  // Embed the featured image as the FIRST <img> in the content so it shows at
  // the top of the editor + public page. URL/alt are HTML-attribute-escaped.
  let bodyHtml = sanitizeHtml(gen.content);
  if (featuredImage && !/<img[^>]*src=/i.test(bodyHtml)) {
    bodyHtml =
      `<p><img src="${escapeHtmlAttr(featuredImage)}" alt="${escapeHtmlAttr(gen.title.slice(0, 200))}" /></p>` +
      bodyHtml;
  }

  const slug = await uniqueSlug(gen.title);

  let article;
  try {
    article = await prisma.article.create({
      data: {
        title: gen.title.slice(0, 250),
        slug,
        content: bodyHtml,
        excerpt: gen.excerpt.slice(0, 500) || null,
        seoTitle: gen.seoTitle ? gen.seoTitle.slice(0, 70) : null,
        seoDescription: gen.metaDescription ? gen.metaDescription.slice(0, 160) : null,
        featuredImage,
        status: "DRAFT",
        // Auto-article DRAFTs are always UNVERIFIED until an editor reviews.
        verificationLabel: "UNVERIFIED",
        isAutoGenerated: true,
        sourceArticleId: null, // web-generated, not a paraphrase of one article
        authorId,
        categoryId,
        // Cite the web sources Perplexity used (deduped by URL, capped at 8).
        sources:
          gen.sources.length > 0
            ? {
                create: dedupeSources(gen.sources)
                  .slice(0, 8)
                  .map((s) => ({
                    name: hostnameOf(s.url),
                    title: s.title ? s.title.slice(0, 250) : null,
                    url: s.url.slice(0, 500),
                  })),
              }
            : undefined,
      },
      select: { id: true, slug: true, title: true },
    });
  } catch (e) {
    return { ok: false, reason: `db-create-failed: ${e instanceof Error ? e.message : String(e)}`, keyword: kw.keyword };
  }

  // Persist suggestedTags (best-effort — tag failures must not abort creation).
  if (gen.suggestedTags.length > 0) {
    const tagsToConnect = gen.suggestedTags
      .filter((t) => t.trim().length > 0)
      .slice(0, 8)
      .map((name) => ({ name: name.trim(), slug: slugify(name.trim()) }));

    if (tagsToConnect.length > 0) {
      await prisma.article
        .update({
          where: { id: article.id },
          data: {
            tags: {
              connectOrCreate: tagsToConnect.map((t) => ({
                where: { slug: t.slug },
                create: { name: t.name, slug: t.slug },
              })),
            },
          },
        })
        .catch((e) => {
          console.error("[auto-article] tag connect fail:", e);
        });
    }
  }

  // Update keyword.lastGeneratedAt (best-effort)
  try {
    await prisma.targetKeyword.update({
      where: { id: kw.id },
      data: { lastGeneratedAt: new Date() },
    });
  } catch {
    /* swallow */
  }

  // Audit log (best-effort)
  try {
    await logAudit(
      null,
      "CRON_AUTO_ARTICLE",
      "article",
      article.id,
      JSON.stringify({
        keyword: kw.keyword,
        provider: "perplexity",
        mode: "perplexity-web",
        sources: gen.sources.length,
        tags: gen.suggestedTags.length,
      }),
    );
  } catch {
    /* swallow */
  }

  return {
    ok: true,
    articleId: article.id,
    slug: article.slug,
    title: article.title,
    keyword: kw.keyword,
    provider: "perplexity",
    tokens: 0,
  };
}

// Convert a stored interval value (string) into a clamped minutes number.
// Allowed values: 5, 10, 15, 20, 30, 60. Anything else → 60.
function parseInterval(raw: string): number {
  const n = Number(raw);
  if ([5, 10, 15, 20, 30, 60].includes(n)) return n;
  return 60;
}

// Clamp batch size to [0, 3]. Editorial cap so a single cron tick never
// floods the queue with more than 3 drafts. 0 means
// "throttle ok but produce nothing".
function parseBatch(raw: string): number {
  const n = Math.floor(Number(raw));
  if (Number.isNaN(n)) return 1;
  if (n < 0) return 0;
  if (n > 3) return 3;
  return n;
}

async function handler(req: NextRequest) {
  const started = Date.now();
  try {
    try { verifyCronSecret(req); } catch (e) { return errorResponse(e); }

    // 1. Advisory lock — prevent concurrent invocations from duplicating work.
    //    Acquire BEFORE the toggle/throttle checks so a concurrent request
    //    that already passed those gates doesn't race into generateOne().
    const LOCK_KEY = "cron:auto-article";
    const lockAcquired = await tryAdvisoryLock(LOCK_KEY);
    if (!lockAcquired) {
      return NextResponse.json(
        {
          success: false,
          skipped: true,
          reason: "ANOTHER_RUN_IN_PROGRESS",
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    try {

    // 2. Toggle check
    const enabledStr = await readSetting("auto_article_enabled", "false");
    if (enabledStr !== "true") {
      return NextResponse.json(
        { success: true, skipped: "disabled", durationMs: Date.now() - started },
        { status: 200 },
      );
    }

    // 3. Throttle check — settings drive how often we actually generate.
    //    The crontab fires the endpoint frequently (every 5 min); this gate
    //    enforces the user's configured cadence without touching crontab.
    const intervalMin = parseInterval(await readSetting("auto_article_interval_minutes", "60"));
    const batchSize = parseBatch(await readSetting("auto_article_batch_size", "1"));
    const lastRunIso = await readSetting("auto_article_last_run_at", "");
    const lastRunAt = lastRunIso ? new Date(lastRunIso) : null;
    const now = new Date();

    if (lastRunAt && !Number.isNaN(lastRunAt.getTime())) {
      const elapsedMin = (now.getTime() - lastRunAt.getTime()) / 60000;
      if (elapsedMin < intervalMin) {
        return NextResponse.json(
          {
            success: true,
            skipped: "throttled",
            intervalMinutes: intervalMin,
            elapsedMinutes: Math.round(elapsedMin * 10) / 10,
            nextRunIn: Math.round((intervalMin - elapsedMin) * 10) / 10,
            durationMs: Date.now() - started,
          },
          { status: 200 },
        );
      }
    }

    // 3. Update last_run_at FIRST so concurrent invocations from a flaky cron
    //    don't double-fire. Even if every generateOne below skips/fails, the
    //    next throttle window will only open after intervalMin from now.
    await writeSetting("auto_article_last_run_at", now.toISOString());

    if (batchSize === 0) {
      return NextResponse.json(
        {
          success: true,
          skipped: "batch-size-zero",
          intervalMinutes: intervalMin,
          batchSize: 0,
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    // 4. Generate batchSize articles. Continue past per-iteration skips/errors
    //    (no keyword, Perplexity throttle, etc.) so a partial batch still
    //    produces something useful.
    const results: GenerateResult[] = [];
    for (let i = 0; i < batchSize; i++) {
      const r = await generateOne();
      results.push(r);
      // No artificial delay — the provider already serialises calls.
    }

    const created = results.filter((r) => r.ok);
    const skipped = results.filter((r) => !r.ok);

    return NextResponse.json(
      {
        success: true,
        intervalMinutes: intervalMin,
        batchSize,
        created: created.length,
        skipped: skipped.length,
        articles: created.map((r) => r.ok ? { id: r.articleId, slug: r.slug, title: r.title, keyword: r.keyword } : null).filter(Boolean),
        skips: skipped.map((r) => !r.ok ? { reason: r.reason, keyword: r.keyword } : null).filter(Boolean),
        durationMs: Date.now() - started,
      },
      { status: 200 },
    );
    } finally {
      // Release lock regardless of success, error, or early return inside the
      // inner try so the next cron tick can acquire it normally.
      await releaseAdvisoryLock(LOCK_KEY);
    }
  } catch (e) {
    // Unexpected error — surface as 5xx so monitoring (UptimeRobot, Sentry)
    // flags an alert. Expected skips (disabled, throttled, lock-held) all
    // return 200 above and never reach here.
    Sentry.captureException(e, { tags: { cron: "auto-article" } });
    console.error("[cron auto-article] UNEXPECTED:", e);
    return NextResponse.json(
      {
        success: false,
        error: e instanceof Error ? e.message : String(e),
        durationMs: Date.now() - started,
      },
      { status: 500 },
    );
  }
}

export async function GET(req: NextRequest) {
  try {
    return await trackCron("auto-article", () => handler(req));
  } catch (e) {
    return errorResponse(e);
  }
}

export async function POST(req: NextRequest) {
  try {
    return await trackCron("auto-article", () => handler(req));
  } catch (e) {
    return errorResponse(e);
  }
}
